//
// Created by kun on 25-7-13.
//

#include "../Inc/user_task.h"
#include "cmsis_os.h"
#include "main.h"
#include "stepper_can.h"
#include "usart.h"

extern osSemaphoreId can_cmd_sem_yawHandle;
extern osSemaphoreId can_cmd_sem_pitchHandle;
extern osThreadId StartUserTaskHandle;

uint8_t yaw_wait_angle_done = 0;
uint8_t pitch_wait_angle_done = 0;

extern float target_yaw_angle, target_pitch_angle;
extern int32_t g_position_yaw, g_position_pitch;

#define READ_PERIOD_MS 10   // 读取周期，不能高于10kHz，建议10ms
#define CTRL_INTERVAL_MS 30 // 控制指令最小间隔

typedef struct {
    enum {
        READ_POS,
        WAIT_READ_RESP,
        SEND_CTRL,
        WAIT_CTRL_RESP
    } state;
    osSemaphoreId sem;
    StepperMotor_Info_t* info;
    float* target_angle;
    int32_t* position;
    uint8_t* wait_angle_done;
    TickType_t last_read_tick;
    TickType_t last_ctrl_tick;
} MotorFSM_t;

void User_Task(void const * argument)
{
    MotorFSM_t motors[2] = {
        {READ_POS, can_cmd_sem_yawHandle, &yaw_motor_Info, &target_yaw_angle, &g_position_yaw, &yaw_wait_angle_done, 0, 0},
        {READ_POS, can_cmd_sem_pitchHandle, &pitch_motor_Info, &target_pitch_angle, &g_position_pitch, &pitch_wait_angle_done, 0, 0}
    };

    for(;;)
    {
        ulTaskNotifyTake(pdTRUE, portMAX_DELAY);

        TickType_t now = osKernelSysTick();

        for (int i = 0; i < 2; ++i) {
            MotorFSM_t* m = &motors[i];
            switch (m->state) {
            case READ_POS:
                if (osSemaphoreGetCount(m->sem) > 0 && now - m->last_read_tick >= READ_PERIOD_MS) {
                    StepperCAN_ReadPosition(m->info->frame_id, NULL);
                    m->last_read_tick = now;
                    m->state = WAIT_READ_RESP;
                }
                break;
            case WAIT_READ_RESP:
                if (osSemaphoreGetCount(m->sem) > 0) {
                    m->state = SEND_CTRL;
                }
                break;
            case SEND_CTRL:
                // 只有未在等待运动完成时才允许下发
                if (*(m->wait_angle_done) == 0 && osSemaphoreGetCount(m->sem) > 0 && now - m->last_ctrl_tick >= CTRL_INTERVAL_MS) {
                    float actual_angle = (float)(*(m->position)) * 360.0f / 65536.0f;
                    float delta = *(m->target_angle) - actual_angle;
                    StepperCAN_SetPositionAngle(m->info, delta, 0x40, 0x20, 0);
                    m->last_ctrl_tick = now;
                    if (delta == 0.0f) {
                        // 角度为0，电机只会应答一次 0x02 6B，直接回到READ_POS
                        *(m->wait_angle_done) = 0;
                        m->state = READ_POS;
                    } else {
                        *(m->wait_angle_done) = 1; // 等待9F 6B
                        m->state = WAIT_CTRL_RESP;
                    }
                }
                break;
            case WAIT_CTRL_RESP:
                // 只有收到9F 6B才允许再次控制
                if (*(m->wait_angle_done) == 0 && osSemaphoreGetCount(m->sem) > 0) {
                    m->state = READ_POS;
                }
                break;
            }
        }

        HAL_GPIO_TogglePin(LED_G_GPIO_Port,LED_G_Pin);
    }
    while(1) { osDelay(1000); }
}

//
// Created by kun on 25-7-13.
//

#include "../Inc/user_task.h"
#include "cmsis_os.h"
#include "main.h"
#include "stepper_can.h"
#include "usart.h"

extern osSemaphoreId can_cmd_sem_yawHandle;
extern osSemaphoreId can_cmd_sem_pitchHandle;
extern osThreadId StartUserTaskHandle;

uint8_t yaw_wait_angle_done = 0;
uint8_t pitch_wait_angle_done = 0;

extern float target_yaw_angle, target_pitch_angle;
extern int32_t g_position_yaw, g_position_pitch;

#define READ_PERIOD_MS 20   // 读取周期20ms
#define CTRL_INTERVAL_MS 50 // 控制指令最小间隔50ms
#define ANGLE_THRESHOLD 0.5f // 角度差值阈值

typedef struct {
    enum {
        IDLE,           // 空闲状态
        READING_POS,    // 正在读取位置
        CONTROLLING     // 正在执行控制
    } state;
    StepperMotor_Info_t* info;
    float* target_angle;
    int32_t* position;
    uint8_t* wait_angle_done;
    TickType_t last_read_tick;
    TickType_t last_ctrl_tick;
} MotorFSM_t;

// 角度转换函数
static float position_to_angle(int32_t position) {
    return (float)position * 360.0f / 65536.0f;
}

void User_Task(void const * argument)
{
    MotorFSM_t motors[2] = {
        {IDLE, &yaw_motor_Info, &target_yaw_angle, &g_position_yaw, &yaw_wait_angle_done, 0, 0},
        {IDLE, &pitch_motor_Info, &target_pitch_angle, &g_position_pitch, &pitch_wait_angle_done, 0, 0}
    };

    uint8_t current_motor = 0; // 当前处理的电机，实现交替控制

    for(;;)
    {
        ulTaskNotifyTake(pdTRUE, portMAX_DELAY);

        TickType_t now = osKernelSysTick();
        MotorFSM_t* m = &motors[current_motor];

        switch (m->state) {
        case IDLE:
            // 检查是否可以开始新的读取周期
            if (*(m->wait_angle_done) == 0 && (now - m->last_read_tick) >= READ_PERIOD_MS) {
                if (StepperCAN_ReadPosition(m->info->frame_id, NULL)) {
                    m->last_read_tick = now;
                    m->state = READING_POS;
                }
            }
            break;

        case READING_POS:
            // 读取位置后，检查是否需要控制
            if (*(m->wait_angle_done) == 0 && (now - m->last_ctrl_tick) >= CTRL_INTERVAL_MS) {
                float actual_angle = position_to_angle(*(m->position));
                float delta = *(m->target_angle) - actual_angle;

                // 只有角度差值超过阈值时才发送控制指令
                if (fabsf(delta) > ANGLE_THRESHOLD) {
                    StepperCAN_SetPositionAngle(m->info, delta, 0x40, 0x20, 0);
                    m->last_ctrl_tick = now;
                    *(m->wait_angle_done) = 1; // 标记正在运动
                    m->state = CONTROLLING;
                } else {
                    m->state = IDLE; // 角度已到位，回到空闲状态
                }
            } else {
                m->state = IDLE; // 回到空闲状态
            }
            break;

        case CONTROLLING:
            // 等待运动完成
            if (*(m->wait_angle_done) == 0) {
                m->state = IDLE;
            }
            break;
        }

        // 交替处理两个电机
        current_motor = (current_motor + 1) % 2;

        HAL_GPIO_TogglePin(LED_G_GPIO_Port,LED_G_Pin);
    }
    while(1) { osDelay(1000); }
}

/* USER CODE BEGIN Header */
/**
  ******************************************************************************
  * @file           : remote_control.c
  * @brief          : remote_control interfaces functions 
  * @author         : Yan Yuanbin
  * @date           : 2023/04/27
  * @version        : v1.0
  ******************************************************************************
  * @attention      : to be tested
  ******************************************************************************
  */
/* USER CODE END Header */

/* Define to prevent recursive inclusion -------------------------------------*/
#ifndef REMOTE_CONTROL_H
#define REMOTE_CONTROL_H

/* Includes ------------------------------------------------------------------*/
#include "config.h"

/* Exported defines -----------------------------------------------------------*/
/**
 * @brief Length of SBUS received data
 */
#define SBUS_RX_BUF_NUM		36u

/**
 * @brief Length of remote control received data
 */
#define RC_FRAME_LENGTH		18u

/**
 * @brief 上位机通信协议相关定义
 */
#define PC_PACKET_HEADER        0x42
#define PC_RX_BUF_SIZE         64u
#define PC_MAX_DATA_LEN        32u
#define PC_MIN_PACKET_SIZE     4u   // 包头+ID+长度+校验和

/**
 * @brief 上位机发送协议相关定义
 */
#define PC_TX_PACKET_HEADER     0x42
#define PC_TX_BUF_SIZE         32u
#define PC_TX_DATA_LEN         8u    // 两个浮点数角度值

/**
 * @brief offset of remote control channel data
 */
#define RC_CH_VALUE_OFFSET		1024U

/**
 * @brief judgement keyboard set short time
 */
#define KEY_SET_SHORT_TIME		50U
/**
 * @brief judgement keyboard set long time
 */
#define KEY_SET_LONG_TIME		1000U

/**
 * @brief status of keyboard up
 */
#define KEY_UP                    0x00U
/**
 * @brief status of keyboard down
 */
#define KEY_DOWN                  0x01U

/**
 * @brief MAX speed of mouse speed
 */
#define MOUSE_SPEED_MAX		300U

/* Exported types ------------------------------------------------------------*/
/**
 * @brief typedef enum that contains the status of the keyboard.
 */
typedef enum
{
	UP,			/*!< up */
	SHORT_DOWN,	/*!< short time down */
	DOWN,		/*!< long time down */
	PRESS,		/*!< 0->1 */
	RELAX,		/*!< 1->0 */
	KeyBoard_Status_NUM,
}KeyBoard_Status_e;

typedef struct
{
	uint16_t Count;
	KeyBoard_Status_e Status;
	KeyBoard_Status_e last_Status;
	bool last_KEY_PRESS;
	bool KEY_PRESS;
}KeyBoard_Info_Typedef;

typedef struct
{
	KeyBoard_Info_Typedef press_l;
	KeyBoard_Info_Typedef press_r;
	KeyBoard_Info_Typedef W;
	KeyBoard_Info_Typedef S;
	KeyBoard_Info_Typedef A;
	KeyBoard_Info_Typedef D;
	KeyBoard_Info_Typedef SHIFT;
	KeyBoard_Info_Typedef CTRL;
	KeyBoard_Info_Typedef Q;
	KeyBoard_Info_Typedef E;
	KeyBoard_Info_Typedef R;
	KeyBoard_Info_Typedef F;
	KeyBoard_Info_Typedef G;
	KeyBoard_Info_Typedef Z;
	KeyBoard_Info_Typedef X;
	KeyBoard_Info_Typedef C;
	KeyBoard_Info_Typedef V;
	KeyBoard_Info_Typedef B;
}Remote_Pressed_Typedef;

/**
 * @brief typedef structure that contains the information for the remote control.
 */
typedef  struct
{
	/**
	 * @brief structure that contains the information for the lever/Switch.
	 */
	struct
	{
		int16_t ch[5];
		uint8_t s[2];
	} rc;

	/**
	 * @brief structure that contains the information for the mouse.
	 */
	struct
	{
		int16_t x;
		int16_t y;
		int16_t z;
		uint8_t press_l;
		uint8_t press_r;
	} mouse;

	/**
	 * @brief structure that contains the information for the keyboard.
	 */
	union
	{
		uint16_t v;
		struct
		{
			uint16_t W:1;
			uint16_t S:1;
			uint16_t A:1;
			uint16_t D:1;
			uint16_t SHIFT:1;
			uint16_t CTRL:1;
